(window.webpackJsonp=window.webpackJsonp||[]).push([[697],{695:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">mat</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">threshold</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxSideLength = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">mat, threshold</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> m=mat.length\\n  <span class=\\"hljs-keyword\\">let</span> n=mat[<span class=\\"hljs-number\\">0</span>].length\\n  <span class=\\"hljs-keyword\\">let</span> maxEdge=<span class=\\"hljs-built_in\\">Math</span>.min(m,n)\\n  <span class=\\"hljs-keyword\\">let</span> s=<span class=\\"hljs-built_in\\">Array</span>(m).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>))\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;m;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(i===<span class=\\"hljs-number\\">0</span> &amp;&amp; j===<span class=\\"hljs-number\\">0</span>)s[i][j]=mat[i][j]\\n      <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(i===<span class=\\"hljs-number\\">0</span>)s[i][j]=s[i][j<span class=\\"hljs-number\\">-1</span>]+mat[i][j]\\n      <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(j===<span class=\\"hljs-number\\">0</span>)s[i][j]=s[i<span class=\\"hljs-number\\">-1</span>][j]+mat[i][j]\\n      <span class=\\"hljs-keyword\\">else</span> s[i][j]=s[i<span class=\\"hljs-number\\">-1</span>][j]+s[i][j<span class=\\"hljs-number\\">-1</span>]-s[i<span class=\\"hljs-number\\">-1</span>][j<span class=\\"hljs-number\\">-1</span>]+mat[i][j]\\n      \\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> nxtL=<span class=\\"hljs-literal\\">false</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> l=<span class=\\"hljs-number\\">1</span>;l&lt;=maxEdge;l++){\\n    nxtL=<span class=\\"hljs-literal\\">false</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;m;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(nxtL)<span class=\\"hljs-keyword\\">break</span>\\n      <span class=\\"hljs-keyword\\">if</span>(i+<span class=\\"hljs-number\\">1</span>&lt;l)<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(j+<span class=\\"hljs-number\\">1</span>&lt;l)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">let</span> leftSum=i-l&lt;<span class=\\"hljs-number\\">0</span> ? <span class=\\"hljs-number\\">0</span> : s[i-l][j]\\n        <span class=\\"hljs-keyword\\">let</span> upSum=j-l&lt;<span class=\\"hljs-number\\">0</span> ? <span class=\\"hljs-number\\">0</span> : s[i][j-l]\\n        <span class=\\"hljs-keyword\\">let</span> upLSum=i-l&lt;<span class=\\"hljs-number\\">0</span> || j-l&lt;<span class=\\"hljs-number\\">0</span> ? <span class=\\"hljs-number\\">0</span> : s[i-l][j-l]\\n        <span class=\\"hljs-keyword\\">let</span> sum=s[i][j]-leftSum-upSum+upLSum\\n        <span class=\\"hljs-comment\\">// console.log(sum,i,j,l)</span>\\n        <span class=\\"hljs-keyword\\">if</span>(sum&lt;=threshold){\\n          res=<span class=\\"hljs-built_in\\">Math</span>.max(res,l)\\n          nxtL=<span class=\\"hljs-literal\\">true</span>\\n          <span class=\\"hljs-keyword\\">break</span>\\n        }  \\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-side-length-of-a-square-with-sum-less-than-or-equal-to-threshold","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u5927\u5c0f\u4e3a\xa0<code>m x n</code>\xa0\u7684\u77e9\u9635\xa0<code>mat</code>\xa0\u548c\u4e00\u4e2a\u6574\u6570\u9608\u503c\xa0<code>threshold</code>\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u5143\u7d20\u603b\u548c\u5c0f\u4e8e\u6216\u7b49\u4e8e\u9608\u503c\u7684\u6b63\u65b9\u5f62\u533a\u57df\u7684\u6700\u5927\u8fb9\u957f\uff1b\u5982\u679c\u6ca1\u6709\u8fd9\u6837\u7684\u6b63\u65b9\u5f62\u533a\u57df\uff0c\u5219\u8fd4\u56de <strong>0\xa0</strong>\u3002<br />\\n\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/12/15/e1.png\\" style=\\"height: 186px; width: 335px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[1,1,3,2,4,3,2],[1,1,3,2,4,3,2],[1,1,3,2,4,3,2]], threshold = 4\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u603b\u548c\u5c0f\u4e8e\u6216\u7b49\u4e8e 4 \u7684\u6b63\u65b9\u5f62\u7684\u6700\u5927\u8fb9\u957f\u4e3a 2\uff0c\u5982\u56fe\u6240\u793a\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[2,2,2,2,2],[2,2,2,2,2],[2,2,2,2,2],[2,2,2,2,2],[2,2,2,2,2]], threshold = 1\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[1,1,1,1],[1,0,0,0],[1,0,0,0],[1,0,0,0]], threshold = 6\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[18,70],[61,1],[25,85],[14,40],[11,96],[97,96],[63,45]], threshold = 40184\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= m, n <= 300</code></li>\\n\\t<li><code>m == mat.length</code></li>\\n\\t<li><code>n == mat[i].length</code></li>\\n\\t<li><code>0 <= mat[i][j] <= 10000</code></li>\\n\\t<li><code>0 <= threshold\xa0<= 10^5</code></li>\\n</ul>\\n","title":"1292. \u5143\u7d20\u548c\u5c0f\u4e8e\u7b49\u4e8e\u9608\u503c\u7684\u6b63\u65b9\u5f62\u7684\u6700\u5927\u8fb9\u957f","relatedTags":["\u6570\u7ec4","\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1292"}')}}]);